{
  "verses": [
    {
      "n": 6,
      "column": "left",
      "text": "Tad tsgahje Eemors / Si-\nkema Tehws/ pee Jehkaba/ ar to\nrunnaht.\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "Un Jehkaba Dehli nahze\nno Lauka/ un kad tee to dsirdeja/\ntad ruhpe tas teem Wihreem/ un\ntee apsaitahs tohti/ tapehz / ka\ntas Gekkibu eeksch Israeta bij\ndarrijs/ gullesdams pee Jehkaba\nMeitas/ kam ta ne bij darriht.\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Un Eemors ruunaja ar\nteem/fazzidams: Sikeena manna\nDehla Sirde peekerrahs juhsu\nMeitai / Dohdeet / luhdsami/\nwinnam to par Seewu.\n"
    },
    {
      "n": 9,
      "column": "left",
      "text": "Un apdrandsinajeetees ar\nmuns / dohdeet muns juhfas\nMeitas / un nemneet preekfch\njums muhfas Meitas.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Un dsihwojeet pee muns/\nnn wiifa ta Semne buhs at-\nwehra juhsu Preekfscha/ mihteet/\nprezzajtees / un petnajtees eeksch\ntahs.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Un Sikeems fazztja us\nwinnas Tehwu/ nn us winnas\nBrahfeem: Laid es Schehlasti-\nbu atrohmu juhfäs Azzis/ un ko\njuhs us man fazzifeet to es doh-\nschu.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Praffajt papillain Kroh-\nno-Nandu un Dahwann / tad\ndebschu es / itt ka juhs us\nman fazzifeet / dohdeet man tik-\nkai to jaunut Meitn par Seewu.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Tad atbildeja Jehkaba\nDehli/ Sikeemam un Eemoram/\nwinna Tehwam ar Wiltu / un\n"
    },
    {
      "n": 6,
      "column": "right",
      "text": "fazzija: Tapehz / ka tas Din-\nwinno Mahfu bij fagahuijis\nun fazzija us teem.\n"
    },
    {
      "n": 14,
      "column": "right",
      "text": "Mehs ne warrain sch-\nLeetu darriht / ka mehs muh-\nMahfu kahdam Wihram doh-\ndam/ kam Preekfsch-Ahda irr/ j\ntas buhtu mums weena Me-\ngantiba.\n"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Tomehr eeksch ta buhfin\nmehs jums paprahtam / ja juh-\ntohpat itt ka mehs / apgraisida-\nmi juhsu Starpâ wiiffu Wih-\nrisfn.\n"
    },
    {
      "n": 16,
      "column": "right",
      "text": "Tad dohfin mehs jum-\nmuhfas Meitas / un nemfin-\nmuns juhfas Meitas / un dsil-\nwosim ar jums kohpä / un buh-\nfin weeni Laudis.\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Bet ja juhs mums n\nflaufifeet/ un apgraisifeetes/ ta-\nnemfin mehs muhsu Meitu/ u-\naiseeim.\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Un tee Wahrdi patif-\nEemoram/ un Sikeemam / E-\nntora Dehlam.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Un tas Jauneklis ne ka-\nwejahs to Leetu darriht/ jo win-\npeemihleja Jehkaba Meitn / u-\ntas bij gohdigi turrehts/pahr wi-\nfu sawu Tehwa Namnu.\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "Tad nahze Eemors / u-\nSikems winna Dehls usta Pil-\nsahta Wahrtim / un runnaja a-\nfawa Pilssahta Wihreem / u-\nfazzija.\n"
    },
    {
      "n": 21,
      "column": "right",
      "text": "Schee Wihri irr meerig-\nar mums/ lai tee schinni Sem-\nmiht/ un prezzejahs/ jo rangi/ t-\nSemmei irr gann plattas Ro-\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
